// Generate realistic AI cost metrics data for cost intelligence analysis

const models = [
  { name: 'gpt-4', inputCostPer1k: 0.03, outputCostPer1k: 0.06 },
  { name: 'gpt-3.5-turbo', inputCostPer1k: 0.0015, outputCostPer1k: 0.002 },
  { name: 'claude-3-opus', inputCostPer1k: 0.015, outputCostPer1k: 0.075 },
  { name: 'claude-3-sonnet', inputCostPer1k: 0.003, outputCostPer1k: 0.015 },
  { name: 'claude-3-haiku', inputCostPer1k: 0.00025, outputCostPer1k: 0.00125 }
];

const workloadTypes = ['customer-support', 'content-generation', 'data-analysis', 'code-generation', 'summarization'];

// Generate metrics for the current period (last 30 days)
const metricsData = [];
const currentDate = new Date();

for (let day = 0; day < 30; day++) {
  const date = new Date(currentDate);
  date.setDate(date.getDate() - day);

  models.forEach(model => {
    workloadTypes.forEach(workload => {
      // Generate realistic usage patterns
      const baseRequests = Math.floor(Math.random() * 5000) + 1000;
      const inputTokens = Math.floor(baseRequests * (Math.random() * 800 + 200));
      const outputTokens = Math.floor(baseRequests * (Math.random() * 400 + 100));

      // Calculate costs
      const inputCost = (inputTokens / 1000) * model.inputCostPer1k;
      const outputCost = (outputTokens / 1000) * model.outputCostPer1k;
      const totalCost = inputCost + outputCost;

      // Generate latency metrics (in milliseconds)
      const avgLatency = Math.floor(Math.random() * 2000) + 500;
      const p95Latency = avgLatency * 1.5;
      const p99Latency = avgLatency * 2;

      metricsData.push({
        date: date.toISOString().split('T')[0],
        model: model.name,
        workload: workload,
        requests: baseRequests,
        inputTokens: inputTokens,
        outputTokens: outputTokens,
        totalTokens: inputTokens + outputTokens,
        inputCost: parseFloat(inputCost.toFixed(4)),
        outputCost: parseFloat(outputCost.toFixed(4)),
        totalCost: parseFloat(totalCost.toFixed(4)),
        avgLatencyMs: avgLatency,
        p95LatencyMs: Math.floor(p95Latency),
        p99LatencyMs: Math.floor(p99Latency),
        errorRate: parseFloat((Math.random() * 0.05).toFixed(4)),
        cacheHitRate: parseFloat((Math.random() * 0.3 + 0.1).toFixed(4))
      });
    });
  });
}

// Calculate summary statistics
const totalCost = metricsData.reduce((sum, m) => sum + m.totalCost, 0);
const totalRequests = metricsData.reduce((sum, m) => sum + m.requests, 0);
const totalTokens = metricsData.reduce((sum, m) => sum + m.totalTokens, 0);
const avgCostPerRequest = totalCost / totalRequests;

// Group by model for cost breakdown
const costByModel = {};
models.forEach(model => {
  const modelMetrics = metricsData.filter(m => m.model === model.name);
  costByModel[model.name] = {
    totalCost: parseFloat(modelMetrics.reduce((sum, m) => sum + m.totalCost, 0).toFixed(2)),
    totalRequests: modelMetrics.reduce((sum, m) => sum + m.requests, 0),
    totalTokens: modelMetrics.reduce((sum, m) => sum + m.totalTokens, 0),
    avgLatency: Math.floor(modelMetrics.reduce((sum, m) => sum + m.avgLatencyMs, 0) / modelMetrics.length)
  };
});

// Group by workload for distribution analysis
const costByWorkload = {};
workloadTypes.forEach(workload => {
  const workloadMetrics = metricsData.filter(m => m.workload === workload);
  costByWorkload[workload] = {
    totalCost: parseFloat(workloadMetrics.reduce((sum, m) => sum + m.totalCost, 0).toFixed(2)),
    totalRequests: workloadMetrics.reduce((sum, m) => sum + m.requests, 0),
    percentage: parseFloat(((workloadMetrics.reduce((sum, m) => sum + m.totalCost, 0) / totalCost) * 100).toFixed(2))
  };
});

return [
  {
    json: {
      period: {
        start: new Date(currentDate.setDate(currentDate.getDate() - 30)).toISOString().split('T')[0],
        end: new Date().toISOString().split('T')[0],
        days: 30
      },
      summary: {
        totalCost: parseFloat(totalCost.toFixed(2)),
        totalRequests: totalRequests,
        totalTokens: totalTokens,
        avgCostPerRequest: parseFloat(avgCostPerRequest.toFixed(6)),
        avgCostPerDay: parseFloat((totalCost / 30).toFixed(2))
      },
      costByModel: costByModel,
      costByWorkload: costByWorkload,
      detailedMetrics: metricsData,
      budget: {
        monthly: 50000,
        current: parseFloat(totalCost.toFixed(2)),
        remaining: parseFloat((50000 - totalCost).toFixed(2)),
        utilizationPercent: parseFloat(((totalCost / 50000) * 100).toFixed(2))
      },
      timestamp: new Date().toISOString()
    }
  }
];

